    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsExpectedFormat()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.AreEqual("(555) 123-4567", result);
        Assert.MatchesRegex(@"\(\d{3}\) \d{3}-\d{4}", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // BuildGreeting tests

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear Mr.", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith("Dear Dr.", result);
        Assert.Contains("Johnson", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.Contains("Smith", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhiteSpace_Throws(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // GenerateSlug tests

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
    {
        var result = _formatter.GenerateSlug("My Post: A Great Read!");

        Assert.MatchesRegex(@"^[a-z0-9\-]+$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithLetter_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.StartsWith("hello", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleEndingWithLetter_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("Hello World!");

        Assert.EndsWith("world", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhiteSpace_Throws(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // FormatCurrency tests

    [TestMethod]
    public void FormatCurrency_WithDefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_WithCustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_WithCents_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(42.5m);

        Assert.AreEqual("$42.50", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.00m);

        Assert.Contains("-", result);
    }
}

